def quicksort(arr):
    if len(arr) <= 1:
        return list(arr)
    mid = len(arr) // 2
    pivot = arr[mid]
    left = [x for i, x in enumerate(arr) if i != mid and x < pivot]
    right = [x for i, x in enumerate(arr) if i != mid and x >= pivot]
    return quicksort(left) + [pivot] + quicksort(right)

