// ReadLines reads a text file and returns its lines as a slice of strings.
// It preserves any trailing whitespace within each line but strips the line terminator.
// It returns an error if the file cannot be opened or read.
func ReadLines(path string) ([]string, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	var lines []string
	scanner := bufio.NewScanner(file)
	for scanner.Scan() {
		line := scanner.Text()
		// Remove the line terminator
		line = line[:len(line)-1]
		// Add the line to the slice
		lines = append(lines, line)
	}

	if err := scanner.Err(); err != nil {
		return nil, err
	}

	return lines, nil
}

func main() {
