import os
import hashlib
import sys

def hash_file(file_path, chunk_size=65536):
    """Hash a file in 64KB chunks."""
    hasher = hashlib.md5()
    with open(file_path, 'rb') as f:
        while True:
            chunk = f.read(chunk_size)
            if not chunk:
                break
            hasher.update(chunk)
    return hasher.hexdigest()

def group_files_by_hash_and_size(directory):
    """Group files by their hash and size."""
    file_groups = {}
    for root, _, files in os.walk(directory):
        for file in files:
            file_path = os.path.join(root, file)
            file_size = os.path.getsize(file_path)
            file_hash = hash_file(file_path)
            if file_size not in file_groups:
                file_groups[file_size] = {}
            if file_hash not in file_groups[file_size]:
                file_groups[file_size][file_hash] = []
            file_groups[file_size][file_hash].append(file_path)
    return file_groups

def print_duplicate_files(file_groups):
    """Print groups of duplicate files."""
    for file_size in file_groups:
        for file_hash in file_groups[file_size]:
            files = file_groups[file_size][file_hash]
            if len(files) > 1:
                print(f"Duplicate files (size {file_size} bytes):")
                for file_path in files:
                    print(file_path)

