import (
    "bufio"
    "fmt"
    "log"
    "net"
    "os"
    "os/signal"
    "sync"
    "syscall"
    "time"
)

var (
    wg       sync.WaitGroup
    listener net.Listener
)

func handleConnection(conn net.Conn) {
    defer wg.Done()
    defer conn.Close()

    connTime := time.Now().Format(time.RFC3339)
    log.Printf("Client connected from %s at %s", conn.RemoteAddr(), connTime)

    reader := bufio.NewReader(conn)
    for {
        message, err := reader.ReadString('\n')
        if err != nil {
            log.Printf("Client %s disconnected: %v", conn.RemoteAddr(), err)
            return
        }
        response := fmt.Sprintf("[%s] Echo: %s", connTime, message)
        _, err = conn.Write([]byte(response))
        if err != nil {
            log.Printf("Write error to %s: %v", conn.RemoteAddr(), err)
            return
        }
    }
}

func main() {
    var err error
    listener, err = net.Listen("tcp", ":8080")
    if err != nil {
        log.Fatalf("Failed to listen: %v", err)
    }
    defer listener.Close()

    log.Printf("TCP server listening on %s", listener.Addr())

    sigChan := make(chan os.Signal, 1)
    signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)

    go func() {
        sig := <-sigChan
        log.Printf("Received signal %v, shutting down...", sig)
        listener.Close()
    }()

    for {
        conn, err := listener.Accept()
        if err != nil {
            if opErr, ok := err.(*net.OpError); ok && opErr.Op == "accept" {
                log.Println("Listener closed, exiting accept loop.")
                break
            }
            log.Printf("Accept error: %v", err)
            continue
        }
        wg.Add(1)
        go handleConnection(conn)
    }

    wg.Wait()
    log.Println("All connections closed. Server shut down gracefully.")
}

