class DebouncedFileWatcher(FileSystemEventHandler):
    EVENT_MAP = {
        'created': 'FILE_CREATED',
        'modified': 'FILE_MODIFIED',
        'deleted': 'FILE_DELETED',
        'moved': 'FILE_MOVED'
    }

    def __init__(self, log_file: str, debounce_seconds: float = 0.5):
        super().__init__()
        self.log_file = Path(log_file)
        self.debounce_seconds = debounce_seconds
        self._last_event = {}
        self._lock = threading.Lock()
        self._log_lock = threading.Lock()

    def _should_process(self, event_path: str) -> bool:
        now = time.time()
        with self._lock:
            last_time = self._last_event.get(event_path, 0)
            if now - last_time < self.debounce_seconds:
                return False
            self._last_event[event_path] = now
            return True

    def _log_event(self, event_type: str, path: str):
        event = {
            "timestamp": datetime.now().isoformat(),
            "event_type": event_type,
            "path": path
        }
        with self._log_lock:
            with open(self.log_file, 'a') as f:
                f.write(json.dumps(event) + '\n')
        logger.info(f"{event_type}: {path}")

    def on_created(self, event):
        if event.is_directory:
            return
        if self._should_process(event.src_path):
            self._log_event(self.EVENT_MAP['created'], event.src_path)

    def on_modified(self, event):
        if event.is_directory:
            return
        if self._should_process(event.src_path):
            self._log_event(self.EVENT_MAP['modified'], event.src_path)

    def on_deleted(self, event):
        if event.is_directory:
            return
        if self._should_process(event.src_path):
            self._log_event(self.EVENT_MAP['deleted'], event.src_path)

    def on_moved(self, event):
        if event.is_directory:
            return
        if self._should_process(event.src_path):
            self._log_event(self.EVENT_MAP['moved'], f"{event.src_path} -> {event.dest_path}")


def watch_directory(directory: str, log_file: str = 'file_events.jsonl'):
    path = Path(directory)
    if not path.exists():
        raise FileNotFoundError(f"Directory not found: {directory}")

    handler = DebouncedFileWatcher(log_file)
    observer = Observer()
    observer.schedule(handler, str(path), recursive=True)
    observer.start()
    logger.info(f"Watching directory: {path} (logs at: {log_file})")

    try:
        while observer.is_alive():
            time.sleep(1)
    except KeyboardInterrupt:
        observer.stop()

    observer.join()
    logger.info("Watcher stopped.")


