        [row[idIdx], row[nameIdx], row[emailIdx]],
        (e) => { if (!e) inserted++; }
      );
    });

    setTimeout(() => {
      console.log(`Processed ${path.basename(filepath)}: inserted ${inserted}/${rows.length}`);
    }, 50);
  });
}

const watcher = chokidar.watch(path.join(DATA_DIR, '*.csv'), { ignoreInitial: false });
