function longestRunIncreasing(arr) {
    if (arr.length === 0) return 0;

    let currentRun = 1;
    let longestRun = 1;

    for (let i = 1; i < arr.length; i++) {
        if (arr[i] > arr[i - 1]) {
            currentRun++;
            longestRun = Math.max(longestRun, currentRun);
        } else {
